patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..f7ab945cfe4e 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -27,7 +27,7 @@
 #include "llvm/IR/Dominators.h"
 #include "llvm/IR/Function.h"
 #include "llvm/IR/IRBuilder.h"
-#include "llvm/IR/InstrTypes.h"
+#include "llvm/IR/InstrTypes.h"\n#include "llvm/IR/IntrinsicInst.h"
 #include "llvm/IR/Instructions.h"
 #include "llvm/IR/Module.h"
 #include "llvm/IR/PatternMatch.h"
@@ -1140,6 +1140,15 @@ void State::addInfoFor(BasicBlock &BB) {
       if (!isGuaranteedNotToBePoison(&I))
         break;
       [[fallthrough]];
+    case Intrinsic::uadd_sat:
+    case Intrinsic::usub_sat:
+    case Intrinsic::sadd_sat:
+    case Intrinsic::ssub_sat:
+      WorkList.push_back(
+          FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
+      if (!isGuaranteedNotToBePoison(&I))
+        break;
+      [[fallthrough]];
     case Intrinsic::abs:
       WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), &I));
       break;
@@ -1898,6 +1907,24 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      if (auto *Sat = dyn_cast<SaturatingInst>(CB.Inst)) {
+        // usub.sat(A, B) <= A (unsigned), uadd.sat(A, B) >= A (unsigned)
+        // ssub.sat(A, B) <= A (signed when no underflow), sadd.sat(A, B) >= A (signed when no overflow)
+        switch (Sat->getIntrinsicID()) {
+        case Intrinsic::usub_sat:
+        case Intrinsic::ssub_sat:
+          AddFact(ICmpInst::ICMP_ULE, Sat, Sat->getLHS());
+          break;
+        case Intrinsic::uadd_sat:
+        case Intrinsic::sadd_sat:
+          AddFact(ICmpInst::ICMP_UGE, Sat, Sat->getLHS());
+          break;
+        default:
+          break;
+        }
+        continue;
+      }
     }

     Value *A = nullptr, *B = nullptr;

